head.script:
scwin.shpco     = "Shpco";  // 선사구분자
scwin.billDtl   = "Dtl"; // 상세구분자          
scwin.billSearchYn = 'NO'; //BILL일자조회 구분자


//물류>청구>청구실적관리/certi/bill 생성 현황 조회
//청구부서 : 6AA, CERTI일자 : 20190901 ~ 20190902

scwin.onpageload = function() {
    //공통코드 적용
    const codeOptions = [
        { grpCd: "FS500", compID: "acb_dcsnClsCd"}      //확정구분 GauceUtil.getCodeList("FS500",GauceUtil.CODE)
    ];

    $c.data.setCommonCode(codeOptions);
};

    //-------------------------------------------------------------------------
 	// 화면로딩시
	//-------------------------------------------------------------------------
	scwin.f_OnLoad = function() {

	};

    scwin.onUdcCompleted = function() {
    //console.log("onUdcCompleted~~");
        scwin.strPreDate = $c.date.getServerDateTime("yyyyMM")+"01";
        scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");// 현재일자를 구한다.

        ed_qryConDtFm.setValue(scwin.strPreDate);
        ed_qryConDtTo.setValue(scwin.strCurDate);
        acb_delYn.setSelectedIndex(1);

        //테스트후 삭제할 것
        //ed_bilgLodeptCd.setValue("6AA");
        //ed_qryConDtFm.setValue("20150901");
        //ed_qryConDtTo.setValue("20150901");

		ed_bilgLodeptCd.focus();
		scwin.f_RetrieveFmalPattern();
		scwin.f_GridFmalPattern();		
		//f_Retrieve();
    };

  	//-------------------------------------------------------------------------
  	// 조회
	//-------------------------------------------------------------------------
	scwin.f_Retrieve = async function() {
//console.log("scwin.f_Retrieve~~");
//console.log(cbx_offsetYn.getValue());
		if(acb_qryConKnd.getValue() == "품명명" || ed_qryConCd.getValue() == ""){
		  	//validation check 
	    	if(!await $c.gus.cfValidate([ed_bilgLodeptCd,ed_qryConDtFm,ed_qryConDtTo])){
	    		return;
	    	}
		}    		 

	  	//조회시작일자가 더 클경우 체크
	  	if (!await $c.gus.cfIsAfterDate(ed_qryConDtFm.getValue(), ed_qryConDtTo.getValue())) {
 	       await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
 	       return;
    	}

     	ds_merchantcertilist_con.set("shpco", scwin.shpco);
   		ds_merchantcertilist_con.set("fmlaClsCd","03");

/*
     	if (cbx_billDtl.checked){
     		ds_merchantcertilist_con.set("billDtl",scwin.billDtl);
     	}else{
            ds_merchantcertilist_con.set("billDtl","");
        }
*/

/*
     	if (cbx_impExpDomesticClsCd01.checked){
     		ds_merchantcertilist_con.set("impExpDomesticClsCd01","I");
     	} 
     	if (cbx_impExpDomesticClsCd02.checked){
     		ds_merchantcertilist_con.set("impExpDomesticClsCd02","O");
     	}
*/
/*
		if (cbx_offsetYn.checked){
     		ds_merchantcertilist_con.set("offsetYn","Y");
     	} else {
     		ds_merchantcertilist_con.set("offsetYn","N");     	
     	}
*/

//console.log("cbx_billDtl.value="+cbx_billDtl.getValue());
//console.log("cbx_billDtl.index="+cbx_billDtl.getSelectedIndex());

        ds_merchantcertilist_con.set("billDtl", cbx_billDtl.getValue());
     	if(acb_qryDtConKnd.getValue() == "CERTI일자"){
     		ds_merchantcertilist_con.set("certiPatternCd","C");
     	} else {
     		ds_merchantcertilist_con.set("certiPatternCd","B");
     	}	

		if(acb_qryConKnd.getValue() == "BILL-NO" && ed_qryConCd.getValue() != "" && cbx_billDtl.getValue() == "Dtl"){     	
     		ds_merchantcertilist_con.set("certiPatternCd","C");     	
     	}

        ds_merchantcertilist_con.set("impExpDomesticClsCd01",cbx_impExpDomesticClsCd01.getValue());
        ds_merchantcertilist_con.set("impExpDomesticClsCd02",cbx_impExpDomesticClsCd02.getValue());

		if (cbx_upClsCd.getValue() != ""){
     		ds_merchantcertilist_con.set("upDownClsCd","UP");
     	} else if(cbx_downClsCd.getValue() != ""){
     		ds_merchantcertilist_con.set("upDownClsCd","DOWN");
     	} else {
     		ds_merchantcertilist_con.set("upDownClsCd","NULL");
     	}

        ds_merchantcertilist_con.set("offsetYn",cbx_offsetYn.getValue());
		if(acb_qryDtConKnd.getValue() == "BILL일자"){
			scwin.billSearchYn = 'YES';
		} else {
			scwin.billSearchYn = 'NO';		
		}

		//상세화면 데이타 Clear
        ds_merchantcertilist.setJSON([]);
        ds_merchantcertidtllist.setJSON([]);
        $c.sbm.execute(sbm_merchantcertilist_retrieve);

        /*
		ds_merchantcertidtllist.ClearData();
		cfShowTotalRows(totalRows2, 0);
        tr_merchantcertilist_retrieve.Action = "/ds.fs.bilg.bilgrsltsmgnt.RetrieveMerchantCertiListCMD.do";
   		tr_merchantcertilist_retrieve.Post();
        */

	};

