	scwin.f_Save = async function() {
	  	if(!ds_merchantcertilist.getModifiedJSON().length != 0){
	  		await $c.gus.cfAlertMsg(MSG_CM_ERR_001,["거래명세서"]);
        	return;
        }	

        if(! await $c.win.confirm(MSG_CM_CRM_001))
        	return;

        $c.sbm.setAction(sbm_merchantcertilist_save, "/ds.fs.bilg.bilgrsltsmgnt.UpdateMerchantCertiCMD.do");
        $c.sbm.execute(sbm_merchantcertilist_save);

        /*
        for (var i=1; i<=ds_merchantcertilist.getRowCount(); i++) {
	        if(ds_merchantcertilist.getCellData(i, "ediSndTrgtYn") == 1){
	        	ds_merchantcertilist.getCellData(i, "ediSndClsCd") = "0";
	        	ds_merchantcertilist.getCellData(i, "ediSndDt") = "";
	        	ds_merchantcertilist.getCellData(i, "ediSndHh") = "";
	        }	
	    } */   

/*
       	tr_merchantcertilist_save.Action = "/ds.fs.bilg.bilgrsltsmgnt.UpdateMerchantCertiCMD.do";
	    tr_merchantcertilist_save.Post();
        */
	};

