	scwin.f_SaveDtl = async function() {
//console.log('scwin.f_SaveDtl~~~');
//console.log('scwin.length~~~'+ds_merchantcertidtllist.getModifiedJSON().length);

	  	if(ds_merchantcertidtllist.getModifiedJSON().length == 0){
	  		await $c.gus.cfAlertMsg(MSG_CM_ERR_001,["거래명세서상세"]);
        	return;        
        }	

        if(!await $c.win.confirm(MSG_CM_CRM_001))
        	return;        

        for (var i=0; i<ds_merchantcertidtllist.getRowCount(); i++) {
	        if(ds_merchantcertidtllist.getCellData(i, "ediSndTrgtYn") == 1){
	        	ds_merchantcertidtllist.setCellData(i, "ediSndClsCd","0");
	        	ds_merchantcertidtllist.setCellData(i, "ediSndDt", "");
	        	ds_merchantcertidtllist.setCellData(i, "ediSndHh", "");
	        }	
	    }

        $c.sbm.execute(sbm_merchantcertidtllist_save);

        /*
		ds_merchantcertilist.UseChangeInfo = "false";
       	tr_merchantcertidtllist_save.Action = "/ds.fs.bilg.bilgrsltsmgnt.UpdateMerchantCertiDtlCMD.do";
	    tr_merchantcertidtllist_save.Post();
        */
	};

