				//rtnList = cfCommonPopUp('retrieveLineInfo',pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);	  			
				//cfSetReturnValue(rtnList, ed_lineCd, txt_lineNm);  // LINE코드, LINE명
