    scwin.gr_merchantcertilist_onrowindexchange = function (rowIndex, oldRow) {
console.log("gr_merchantcertilist_onrowindexchange~~~");
        //<script language=JavaScript for=ds_merchantcertilist event=OnLoadCompleted(rowcnt)>
        //cfHideDSWaitMsg(gr_merchantcertilist);
        //cfShowTotalRows(totalRows, rowcnt);

        /*
        if (rowcnt == 0) {
            cfAlertMsg(MSG_CM_WRN_002);
            ed_bilgLodeptCd.Focus();
        }
        */
        var rowcnt = ds_merchantcertilist.getRowCount();
        if(rowcnt > 0){
            //scwin.f_GetDataSet("1");
            scwin.f_GetDataSet(rowIndex);
        }	
    };

    scwin.gr_merchantcertilist_oncellclick = async function (rowIndex, columnIndex, columnId) {
console.log("gr_merchantcertilist_oncellclick~~~");
        //<script language=JavaScript for=gr_merchantcertilist event=OnClick(row,colid)>
        var rowcnt = ds_merchantcertilist.getRowCount();
        if(rowcnt > 0){
            if (columnId == "certiNo" && ds_merchantcertilist.getCellData(rowIndex, "certiNo") != ""){ 
                scwin.f_certiNoDetail();
            } else if (columnId == "slipNo" && ds_merchantcertilist.getCellData(rowIndex, "slipNo") != ""){ 
                await $c.gus.cfShowSlipInfo(ds_merchantcertilist.getCellData(rowIndex,"slipNo"));
                //scwin.f_GetDataSet(rowIndex);
            } else {
                //scwin.f_GetDataSet(rowIndex);	
            }
        }
    };

	scwin.udc_bilgLodeptCdCallback = function(ret){
        scwin.f_setUdcPopCallback(ret,ed_bilgLodeptCd,ed_bilgLodeptNm);
    };

	scwin.udc_lineCdCallback = function(ret){
        scwin.f_setUdcPopCallback(ret,ed_lineCd,ed_lineNm);
    };

	scwin.udc_modIdCallback = function(ret){
        scwin.f_setUdcPopCallback(ret,ed_modId,ed_modNm);
    };

//udc팝업공통 콜백처리
scwin.f_setUdcPopCallback = function(ret,objCode,objName){
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if (rtnList[0] == "N/A"){
				objCode.setValue("");
                objName.setValue("");
                objCode.hidVal = "";
				return;
			}
			objCode.setValue(rtnList[0]);	// 코드값
			objName.setValue(rtnList[1]);	// 코드명
            objCode.hidVal = rtnList[0];	// 코드값
		} else {
			objCode.setValue("");
			objName.setValue("");
            objCode.hidVal = "";
		}

    } catch (e) {
       console.log(e);
    }
};

