  	//-------------------------------------------------------------------------
  	// EDI전송
  	//-------------------------------------------------------------------------  	
	scwin.f_EdiSave = async function(){
		if(ds_merchantcertilist.getRowCount() < 1){
	       	await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
	       	return;	
		}

	  	if(!ds_merchantcertilist.getModifiedJSON().length != 0){
	  		await $c.gus.cfAlertMsg(MSG_CM_ERR_001,["EDI전송 대상여부"]);
        	return;        
        }		

		if(scwin.billSearchYn == "YES"){
			if(cbx_billDtl.getValue() == "Dtl"){
		       	await $c.gus.cfAlertMsg("BILL 상세에서는 EDI전송 처리할 수 없습니다.");
		       	return;				
			} else {
		        if(! await $c.win.confirm("EDI 전송 처리하시겠습니까?"))
        		return;        

                $c.sbm.setAction(sbm_merchantcertilist_save, "/ds.fs.bilg.bilgrsltsmgnt.UpdateBillEdiCMD.do");
                $c.sbm.execute(sbm_merchantcertilist_save);

				//ds_merchantcertidtllist.UseChangeInfo = "false";

       			//tr_merchantcertilist_save.Action = "/ds.fs.bilg.bilgrsltsmgnt.UpdateBillEdiCMD.do";
			    //tr_merchantcertilist_save.Post();

			}
		} else {
	       	await $c.gus.cfAlertMsg("BILL 일자로 조회해야만 EDI전송 처리할 수 있습니다.");
	       	return;	
		}		
	};

