scwin.gr_merchantcertilist_onviewchange = function (info) {
    console.log("scwin.gr_merchantcertilist_onviewchange ~~");
    //console.log(info);
    var colid = info.colId;
    var row = info.rowIndex;

    if(row > 0 && colid == "ediSndTrgtYn"){
		if(ds_merchantcertilist.getCellData(row, "ediSndTrgtYn") == 0){ 
			ds_merchantcertilist.setCellData(row, "ediSndTrgtYn", 1);
		} else {
			if(ds_merchantcertilist.getCellData(row, "ediSndDt") != ""){ 
		       	$c.gus.cfAlertMsg("이미 전송된 건은 재전송할 수 없습니다.");
				ds_merchantcertilist.setCellData(row, "ediSndTrgtYn", 0);
			}			
		}
	}
};

scwin.acb_qryConKnd_onviewchange = function (info) {
//console.log(info);
    if(info.newValue=='품명명'){
        ed_qryConCd.setAllowChar("");
    }else{
        ed_qryConCd.setAllowChar("A-Z0-9");
    }
    ed_qryConCd.setValue("");
};

